import{_ as e,c as s,o as r,ah as i}from"./chunks/framework.C-x9UAyH.js";const m=JSON.parse('{"title":"IaaS (Infrastructure as a Service)","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"aws/modelo_de_servicios/iaas.md","filePath":"aws/modelo_de_servicios/iaas.md","lastUpdated":1760459112000}'),o={name:"aws/modelo_de_servicios/iaas.md"};function n(t,a,l,u,c,d){return r(),s("div",null,[...a[0]||(a[0]=[i('<h1 id="iaas-infrastructure-as-a-service" tabindex="-1">IaaS (Infrastructure as a Service) <a class="header-anchor" href="#iaas-infrastructure-as-a-service" aria-label="Permalink to &quot;IaaS (Infrastructure as a Service)&quot;">​</a></h1><p>Proporciona a las organizaciones los componentes básicos de la infraestructura de TI, como máquinas virtuales, almacenamiento y redes. Las organizaciones son responsables de administrar y mantener esta infraestructura.</p><h2 id="algunos-servicios-de-iaas" tabindex="-1">Algunos servicios de IaaS <a class="header-anchor" href="#algunos-servicios-de-iaas" aria-label="Permalink to &quot;Algunos servicios de IaaS&quot;">​</a></h2><ul><li><p><strong>Amazon Elastic Compute Cloud (EC2)</strong>: proporciona instancias de <em>servidor virtual</em> escalables e instantáneas que se pueden iniciar, detener y escalar según sea necesario.</p></li><li><p><strong>Amazon Simple Storage Service (S3)</strong>: es un servicio de <em>almacenamiento</em> en la nube que permite a los usuarios almacenar y recuperar datos de manera segura y escalable, facilitando la gestión de archivos y objetos a través de una interfaz web sencilla.</p></li><li><p><strong>Amazon Virtual Private Cloud (VPC)</strong>: proporciona a los usuarios una <em>red virtual</em> privada en la nube que se puede aislar de la red pública.</p></li><li><p><strong>Amazon Route 53</strong>: proporciona servicios de DNS que permiten a los usuarios dirigir el tráfico web a sus aplicaciones en la nube.</p></li></ul><h2 id="ventajas" tabindex="-1">Ventajas <a class="header-anchor" href="#ventajas" aria-label="Permalink to &quot;Ventajas&quot;">​</a></h2><ul><li>Flexibilidad: los usuarios pueden escalar sus recursos según sea necesario.</li><li>Ahorro de costos: los usuarios solo pagan por los recursos que utilizan.</li><li>Control: los usuarios tienen control total sobre su infraestructura.</li></ul><h2 id="desventajas" tabindex="-1">Desventajas <a class="header-anchor" href="#desventajas" aria-label="Permalink to &quot;Desventajas&quot;">​</a></h2><ul><li>Complejidad: Los usuarios deben administrar sus propios recursos.</li><li>Seguridad: Los usuarios son responsables de la seguridad de sus datos.</li></ul><h2 id="importante" tabindex="-1">Importante <a class="header-anchor" href="#importante" aria-label="Permalink to &quot;Importante&quot;">​</a></h2><p>La elección del modelo de servicio adecuado dependerá de las necesidades específicas de la organización.</p><ul><li>Las organizaciones que necesitan un alto grado de control sobre su infraestructura deben considerar IaaS.</li><li>Las organizaciones que buscan una solución sencilla y sin complicaciones deben considerar SaaS.</li><li>Las organizaciones que necesitan una plataforma para desarrollar y ejecutar aplicaciones deben considerar PaaS.</li></ul>',11)])])}const v=e(o,[["render",n]]);export{m as __pageData,v as default};
